<?php
namespace App\Models;use App\Models\Concerns\BelongsToHotel;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;
class GuestServiceRequest extends Model{use BelongsToHotel;protected $fillable=['hotel_id','guest_id','checkin_id','room_id','type','status','priority','details','housekeeping_task_id','maintenance_work_order_id','completed_at','guest_confirmed_at','completion_photo','cancelled_at'];protected function casts():array{return['completed_at'=>'datetime','guest_confirmed_at'=>'datetime','cancelled_at'=>'datetime'];}public function guest():BelongsTo{return $this->belongsTo(Guest::class);}public function room():BelongsTo{return $this->belongsTo(Room::class);}public function housekeepingTask():BelongsTo{return $this->belongsTo(HousekeepingTask::class);}public function maintenanceWorkOrder():BelongsTo{return $this->belongsTo(MaintenanceWorkOrder::class);}public function messages(){return$this->hasMany(GuestRequestMessage::class);}public function events(){return$this->hasMany(GuestRequestEvent::class);}}
